@group(0) @binding(0) var<uniform> time: f32;
@group(0) @binding(1) var<uniform> thickness: f32;

fn sdBox(p: vec2<f32>, b: vec2<f32>) -> f32 {
    let d = abs(p) - b;
    return length(max(d, vec2<f32>(0.0))) + min(max(d.x, d.y), 0.0);
}

@fragment
fn main(@builtin(position) pos: vec4<f32>) -> @location(0) vec4<f32> {
    let uv = (pos.xy / vec2<f32>(800.0, 600.0)) * 2.0 - 1.0;
    let angle = time * 0.5;
    let c = cos(angle);
    let s = sin(angle);
    let rotated = vec2<f32>(uv.x * c - uv.y * s, uv.x * s + uv.y * c);
    let d1 = abs(sdBox(rotated, vec2<f32>(0.4, 0.4))) - thickness;
    let d2 = abs(length(uv) - 0.5) - thickness;
    let shape1 = smoothstep(0.01, 0.0, d1);
    let shape2 = smoothstep(0.01, 0.0, d2);
    let r = shape1 * 0.8 + shape2 * 0.2;
    let g = shape2 * 0.7;
    let b = shape1 * 0.3 + shape2 * 0.9;
    return vec4<f32>(r, g, b, 1.0);
}
